describe("getNewsRecommendationSourceSaturation", () => {
  it("flags a recommendation queue dominated by one source", () => {
    expect(
      getNewsRecommendationSourceSaturation({
        items: [
          {
            ...localItem,
            id: "model-desk-lead",
            matchedSignals: [],
            personalizedScore: 120,
            sourceName: "Model Desk",
            sourceSlug: "model-desk",
          },
          {
            ...localItem,
            id: "model-desk-follow-up",
            matchedSignals: [],
            personalizedScore: 110,
            sourceName: "Model Desk",
            sourceSlug: "model-desk",
          },
          {
            ...localItem,
            id: "agent-scout-alt",
            matchedSignals: [],
            personalizedScore: 100,
            sourceName: "Agent Scout",
            sourceSlug: "agent-scout",
          },
          {
            ...localItem,
            id: "model-desk-analysis",
            matchedSignals: [],
            personalizedScore: 90,
            sourceName: "Model Desk",
            sourceSlug: " model-desk ",
          },
        ],
        limit: 4,
      }),
    ).toEqual({
      actions: [
        {
          detail:
            "Model Desk owns 3 of 4 recommendation slots; bring in independent sources before the next ranking pass.",
          label: "Expand source mix",
          trainingSignal: {
            effect: "remove",
            kind: "source",
            label: "Model Desk",
            signal: "model-desk",
          },
        },
        {
          detail:
            "Agent Scout is available as the strongest alternative source in this queue.",
          label: "Candidate source",
          trainingSignal: {
            effect: "add",
            kind: "source",
            label: "Agent Scout",
            signal: "agent-scout",
          },
        },
      ],
      label: "Source Saturated",
      metrics: [
        { label: "Slots", value: "4" },
        { label: "Sources", value: "2" },
        { label: "Dominant share", value: "75%" },
        { label: "Repeat slots", value: "3" },
      ],
      summary:
        "Model Desk owns 75% of the next 4 recommendation slots across 2 sources.",
    });
  });

  it("turns saturated source controls into profile training actions", () => {
    const saturation = getNewsRecommendationSourceSaturation({
      items: [
        {
          ...localItem,
          id: "model-desk-lead",
          matchedSignals: [],
          personalizedScore: 120,
          sourceName: "Model Desk",
          sourceSlug: "model-desk",
        },
        {
          ...localItem,
          id: "model-desk-follow-up",
          matchedSignals: [],
          personalizedScore: 110,
          sourceName: "Model Desk",
          sourceSlug: "model-desk",
        },
        {
          ...localItem,
          id: "agent-scout-alt",
          matchedSignals: [],
          personalizedScore: 100,
          sourceName: "Agent Scout",
          sourceSlug: "agent-scout",
        },
      ],
      limit: 3,
    });
    const [reduceAction, candidateAction] = saturation.actions;

    expect(reduceAction).toBeDefined();
    expect(candidateAction).toBeDefined();
    if (!reduceAction || !candidateAction) return;

    expect(getNewsRecommendationSaturationTrainingAction(reduceAction)).toEqual(
      {
        actionLabel: "Reduce source",
        effect: "remove",
        label: "Model Desk",
        signals: [
          {
            kind: "source",
            label: "Model Desk",
            signal: "model-desk",
          },
        ],
        source: "control",
      },
    );
    expect(
      getNewsRecommendationSaturationTrainingAction(candidateAction),
    ).toEqual({
      actionLabel: "Follow source",
      effect: "add",
      label: "Agent Scout",
      signals: [
        {
          kind: "source",
          label: "Agent Scout",
          signal: "agent-scout",
        },
      ],
      source: "control",
    });
  });

  it("keeps source saturation stable before recommendation slots arrive", () => {
    expect(
      getNewsRecommendationSourceSaturation({
        items: [],
        limit: 4,
      }),
    ).toEqual({
      actions: [
        {
          detail:
            "Wait for ranked stories before checking whether one source dominates the recommendation queue.",
          label: "Wait for ranking",
        },
      ],
      label: "Saturation Waiting",
      metrics: [
        { label: "Slots", value: "0" },
        { label: "Sources", value: "0" },
        { label: "Dominant share", value: "0%" },
        { label: "Repeat slots", value: "0" },
      ],
      summary:
        "Source saturation will appear after recommendation slots are ranked.",
    });
  });
});

