describe("selectStoredNewsPositiveFeedbackItems", () => {
  beforeEach(() => {
    vi.useFakeTimers();
    vi.setSystemTime(new Date("2026-07-02T10:00:00.000Z"));
  });

  afterEach(() => {
    vi.useRealTimers();
  });

  it("keeps explicit and read positive feedback entries from storage", () => {
    expect(
      selectStoredNewsPositiveFeedbackItems([
        {
          action: "share",
          category: "model_release",
          entities: ["OpenAI", 42, "Agents"],
          id: "local-share",
          occurredAt: "2026-07-01T10:00:00.000Z",
          sourceName: "OpenAI News",
          sourceSlug: "openai-news",
          tags: ["model", 7, "agent"],
          title: "OpenAI releases a new agent stack",
        },
        {
          action: "click_source",
          category: "market_map",
          entities: ["Anthropic"],
          id: "local-source-click",
          occurredAt: "2026-07-01T10:30:00.000Z",
          sourceName: "Source Desk",
          sourceSlug: "source-desk",
          title: "Source registry covers labs",
        },
        {
          category: "agent_product",
          entities: ["OpenAI"],
          id: "local-deep-read",
          occurredAt: "2026-07-01T10:45:00.000Z",
          sourceName: "Agent Desk",
          sourceSlug: "agent-desk",
          tags: ["agents"],
          title: "Reader finished an agent story",
        },
        {
          action: "hide",
          category: "policy",
          entities: ["Policy"],
          id: "not-positive",
          occurredAt: "2026-07-01T11:00:00.000Z",
          sourceName: "Policy Desk",
          sourceSlug: "policy-desk",
          title: "Invalid action",
        },
        {
          action: "save",
          category: "research",
          entities: ["Benchmarks"],
          id: "missing-occurred-at",
          sourceName: "Research Desk",
          sourceSlug: "research-desk",
          title: "Missing timestamp",
        },
        null,
      ]),
    ).toEqual([
      {
        category: "agent_product",
        entities: ["OpenAI"],
        id: "local-deep-read",
        occurredAt: "2026-07-01T10:45:00.000Z",
        sourceName: "Agent Desk",
        sourceSlug: "agent-desk",
        tags: ["agents"],
        title: "Reader finished an agent story",
      },
      {
        action: "click_source",
        category: "market_map",
        entities: ["Anthropic"],
        id: "local-source-click",
        occurredAt: "2026-07-01T10:30:00.000Z",
        sourceName: "Source Desk",
        sourceSlug: "source-desk",
        title: "Source registry covers labs",
      },
      {
        action: "share",
        category: "model_release",
        entities: ["OpenAI", "Agents"],
        id: "local-share",
        occurredAt: "2026-07-01T10:00:00.000Z",
        sourceName: "OpenAI News",
        sourceSlug: "openai-news",
        tags: ["model", "agent"],
        title: "OpenAI releases a new agent stack",
      },
    ]);
  });

  it("returns the newest stored positive feedback entries within the configured limit", () => {
    expect(
      selectStoredNewsPositiveFeedbackItems(
        [
          {
            action: "share",
            category: "model_release",
            entities: ["OpenAI"],
            id: "old-share",
            occurredAt: "2026-07-01T08:00:00.000Z",
            sourceName: "OpenAI News",
            sourceSlug: "openai-news",
            title: "Old share",
          },
          {
            action: "save",
            category: "agent_product",
            entities: ["Agents"],
            id: "recent-save",
            occurredAt: "2026-07-01T10:00:00.000Z",
            sourceName: "Agent Desk",
            sourceSlug: "agent-desk",
            title: "Recent save",
          },
          {
            action: "click_source",
            category: "research",
            entities: ["Benchmarks"],
            id: "recent-source",
            occurredAt: "2026-07-01T09:30:00.000Z",
            sourceName: "Research Desk",
            sourceSlug: "research-desk",
            title: "Recent source",
          },
          {
            action: "share",
            category: "funding",
            entities: ["Runway"],
            id: "new-share",
            occurredAt: "2026-07-01T10:30:00.000Z",
            sourceName: "Funding Desk",
            sourceSlug: "funding-desk",
            title: "New share",
          },
        ],
        { limit: 3 },
      ).map((item) => item.id),
    ).toEqual(["new-share", "recent-save", "recent-source"]);
  });

  it("drops future-dated positive feedback before it can shape local recommendations", () => {
    const currentOccurredAt = new Date(Date.now() - 24 * 60 * 60 * 1000)
      .toISOString()
      .replace(/\.\d{3}Z$/, ".000Z");
    const futureOccurredAt = new Date(Date.now() + 24 * 60 * 60 * 1000)
      .toISOString()
      .replace(/\.\d{3}Z$/, ".000Z");

    expect(
      selectStoredNewsPositiveFeedbackItems([
        {
          action: "share",
          category: "model_release",
          entities: ["OpenAI"],
          id: "current-share",
          occurredAt: currentOccurredAt,
          sourceName: "OpenAI News",
          sourceSlug: "openai-news",
          title: "Current share",
        },
        {
          action: "save",
          category: "agent_product",
          entities: ["Agents"],
          id: "future-save",
          occurredAt: futureOccurredAt,
          sourceName: "Agent Desk",
          sourceSlug: "agent-desk",
          title: "Future save",
        },
      ]),
    ).toEqual([
      {
        action: "share",
        category: "model_release",
        entities: ["OpenAI"],
        id: "current-share",
        occurredAt: currentOccurredAt,
        sourceName: "OpenAI News",
        sourceSlug: "openai-news",
        title: "Current share",
      },
    ]);
  });

  it("drops stale source-click feedback while keeping durable positive feedback", () => {
    const staleOccurredAt = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000)
      .toISOString()
      .replace(/\.\d{3}Z$/, ".000Z");

    expect(
      selectStoredNewsPositiveFeedbackItems([
        {
          action: "click_source",
          category: "agent_product",
          entities: ["Agents"],
          id: "stale-source-click",
          occurredAt: staleOccurredAt,
          sourceName: "Agent Desk",
          sourceSlug: "agent-desk",
          title: "Stale source click",
        },
        {
          action: "save",
          category: "model_release",
          entities: ["OpenAI"],
          id: "durable-save",
          occurredAt: staleOccurredAt,
          sourceName: "OpenAI News",
          sourceSlug: "openai-news",
          title: "Durable save",
        },
        {
          action: "share",
          category: "funding",
          entities: ["Runway"],
          id: "durable-share",
          occurredAt: staleOccurredAt,
          sourceName: "Funding Desk",
          sourceSlug: "funding-desk",
          title: "Durable share",
        },
        {
          category: "research",
          entities: ["Benchmarks"],
          id: "durable-deep-read",
          occurredAt: staleOccurredAt,
          sourceName: "Research Desk",
          sourceSlug: "research-desk",
          title: "Durable deep read",
        },
      ]).map((item) => item.id),
    ).toEqual(["durable-deep-read", "durable-save", "durable-share"]);
  });
});

